(window.webpackJsonp=window.webpackJsonp||[]).push([[3],{232:function(e){e.exports={data:{allProject:{edges:[{node:{id:"351ab05711da5896099a0464cfe95584",title:"Getting in Trouble",path:"/projects/gettingintrouble",content:'<p>Submitted entry for the Global Game Jam 2019. The game was created in 48h and with the theme "What home means to you" in mind.</p>\n',image:"/images/gettingintrouble.png",date:"2019-01-27",github:"",gitlab:"",link:"https://globalgamejam.org/2019/games/getting-trouble"}},{node:{id:"33216c46af96878f9ab9bc6bc6368a37",title:"Advent of Code 2018",path:"/projects/adventofcode2018",content:'<p>Solution for the <a href="https://adventofcode.com/2018" target="_blank" rel="nofollow noopener noreferrer">Advent of Code 2018</a> puzzles written in TypeScript using <a href="https://github.com/TypeStrong/ts-node" target="_blank" rel="nofollow noopener noreferrer">ts-node</a></p>\n<p>I did try to reach the global Leader Bord for three times (22th, 23th, 24th) but did not make it.\n<a href="https://docs.google.com/spreadsheets/d/e/2PACX-1vTZM_8TT8_fgYd97hgJXcYxSJ0Z_dIItW90d77EYQgaBe71Fg5y0OHIU9j3vb8hb3LqqRzLxNh-lq-W/pubhtml#" target="_blank" rel="nofollow noopener noreferrer">Google Sheet</a> with my scores and placements in the Global Ranking.</p>\n',image:"/images/aoc2018.png",date:"2018-12-01",github:"",gitlab:"https://gitlab.com/EldoranDev/adventofcode",link:"https://eldorandev.gitlab.io/adventofcode"}},{node:{id:"df1160398b494dd446a78f51755ee22b",title:"Spatholobus",path:"/projects/spatholobus",content:'<p>Submitted entry for the Global Game Jam 2018. The game was created in 48h and with the theme "Transmission" in mind.</p>\n<p>Used diversifiers:</p>\n<ul>\n<li>DESIGN - Nem tão próximos</li>\n<li>DESIGN - Created by Warren Robinett</li>\n<li>META - Special:Random</li>\n</ul>\n',image:"/images/spatholobus.png",date:"2018-01-25",github:"",gitlab:"",link:"https://globalgamejam.org/2018/games/spatholobus"}},{node:{id:"b47c6e703b6906d8393f377a69220331",title:"CSLox",path:"/projects/cslox",content:'<p>C# implementation of jlox, the script langauge created in the book <a href="http://craftinginterpreters.com/" target="_blank" rel="nofollow noopener noreferrer">Crafting Interpreters</a>.\nThis implementation should be able to run all jlox scripts.</p>\n<p>This implementation is currently not tested with .net core but it should be portable without mutch work.</p>\n',image:"/images/cslox.png",date:"2017-11-06",github:"https://github.com/EldoranDev/cslox",gitlab:"",link:""}}]}}}}}]);